function normalized(buffer){return Buffer.from(buffer.toString('utf8').replace(/\r\n/g,'\n').replace(/\r/g,'\n'),'utf8');}
function digest(buffer){return createHash('sha256').update(normalized(buffer)).digest('hex');}
function detectEol(buffer){return buffer.includes(Buffer.from('\r\n'))?'\r\n':'\n';}
function withEol(buffer,eol){return Buffer.from(normalized(buffer).toString('utf8').replace(/\n/g,eol),'utf8');}
function payload(entry){const data=gunzipSync(Buffer.from(entry.payload,'base64'));if(digest(data)!==entry.finalHash)fail('내장 payload 해시 검증 실패');return data;}
function relPath(root,rel){return join(root,...rel.split('/'));}
function log(message=''){console.log(`[Refactor 013G] ${message}`);}
function fail(message){throw new Error(message);}

function isRoot(path){return existsSync(join(path,'package.json'))&&existsSync(join(path,'shared','src','maps','dock8.ts'))&&existsSync(join(path,'server','src','rooms','Drop8Room.ts'))&&existsSync(join(path,'client','src','GameScene.ts'));}
function findRoot(){
  const seeds=[process.cwd(),dirname(fileURLToPath(import.meta.url))];
  for(const seed of seeds){let current=resolve(seed);for(let depth=0;depth<8;depth++){if(isRoot(current))return current;const parent=dirname(current);if(parent===current)break;current=parent;}}
  fail('프로젝트 루트를 찾지 못했습니다. 이 파일을 DROP8_SOURCE 최상위 폴더에 두고 실행하세요.');
}

function inspect(root){
  const final=[];const baseline=[];const conflicts=[];const absent=[];
  for(const [rel,entry] of Object.entries(FILES)){
    const path=relPath(root,rel);
    if(!existsSync(path)){if(entry.newFile)absent.push(rel);else conflicts.push(`${rel}: 필수 기준 파일 없음`);continue;}
    const currentHash=digest(readFileSync(path));
    if(currentHash===entry.finalHash)final.push(rel);
    else if(entry.baselineHash&&currentHash===entry.baselineHash)baseline.push(rel);
    else conflicts.push(`${rel}: 예상하지 못한 내용 (SHA256 ${currentHash})`);
  }
  return{final,baseline,conflicts,absent};
}

function prerequisiteCheck(root){
  const shared=readFileSync(join(root,'shared','src','index.ts'),'utf8');
  const dock=readFileSync(join(root,'shared','src','maps','dock8.ts'),'utf8');
  const room=readFileSync(join(root,'server','src','rooms','Drop8Room.ts'),'utf8');
  const client=readFileSync(join(root,'client','src','GameScene.ts'),'utf8');
  const required=[
    ['Refactor 013 공용 마커',shared.includes(BASE_MARKER)&&room.includes(BASE_MARKER)],
    ['Dock 8 7168 맵',dock.includes('DOCK8_WORLD_SIZE=7168')||dock.includes('DOCK8_WORLD_SIZE = 7168')],
    ['roomIndex 공간 시스템',shared.includes('roomIndex')&&room.includes('roomIndex')],
    ['수영 상태와 깊은 물 판정',room.includes('isSwimming')&&room.includes('isDeepWaterAt')],
    ['기존 내부 시야 캔버스',client.includes('windowVisibilityOverlay')&&client.includes('updateWindowVisionOverlay')],
    ['013 FIXED v2 오토바이 기준',dock.includes('DOCK8_MOTORCYCLE_SPAWNS')],
  ];
  const failed=required.filter(([,ok])=>!ok).map(([name])=>name);
  if(failed.length)fail(`Refactor 013 FIXED v2 기준 검증 실패: ${failed.join(', ')}`);
}

function validateFinalFiles(root){
  for(const [rel,entry] of Object.entries(FILES)){
    const path=relPath(root,rel);if(!existsSync(path))fail(`결과 파일 누락: ${rel}`);
    const content=readFileSync(path);if(digest(content)!==entry.finalHash)fail(`결과 해시 불일치: ${rel}`);
    if(!normalized(content).toString('utf8').endsWith('\n'))fail(`EOF 개행 누락: ${rel}`);
  }
  const shared=readFileSync(join(root,'shared','src','index.ts'),'utf8');
  const dock=readFileSync(join(root,'shared','src','maps','dock8.ts'),'utf8');
  const server=readFileSync(join(root,'server','src','rooms','Drop8Room.ts'),'utf8');
  const client=readFileSync(join(root,'client','src','GameScene.ts'),'utf8');
  const mapTest=readFileSync(join(root,'shared','tests','refactor013-map.test.ts'),'utf8');
  const serverTest=readFileSync(join(root,'server','tests','refactor013g-dock8-recovery.test.ts'),'utf8');
  for(const [name,text] of [['shared',shared],['dock8',dock],['server',server],['client',client],['map test',mapTest],['server test',serverTest]])if(!text.includes(PATCH_MARKER))fail(`${name} 013G 적용 마커 누락`);
  const checks=[
    ['Dock 8 전리품 예산 216',shared.includes('lootBudget:216')],
    ['Dock 8 오토바이 예산 8',shared.includes('motorcycleBudget:8')],
    ['전리품 후보 264',dock.includes('.slice(0,264)')],
    ['오토바이 후보 12',dock.match(/bike-dock8-/g)?.length===12],
    ['균형 차량 선택',server.includes('selectMotorcycleSpawns')&&server.includes("this.map.id!=='dock8'")],
    ['현재 방 전체 화면 가림 제거',!client.includes("context.fillStyle='rgba(2,7,11,.74)'")],
    ['현재 방 지붕 즉시 제거',client.includes('if(id===buildingId)roof.setAlpha(0)')],
    ['실내 전리품 검증',mapTest.includes('more than half of active Dock 8 loot indoors')],
    ['서버 생성 검증',serverTest.includes('spawns 216 loot items')&&serverTest.includes('selects eight motorcycles')],
  ];
  const failed=checks.filter(([,ok])=>!ok).map(([name])=>name);
  if(failed.length)fail(`013G 핵심 구현 검증 실패: ${failed.join(', ')}`);
}

function backup(root){
  const backupRoot=join(root,BACKUP_DIR);
  if(existsSync(backupRoot))rmSync(backupRoot,{recursive:true,force:true});
  mkdirSync(backupRoot,{recursive:true});
  const manifest={patch:PATCH_NAME,createdAt:new Date().toISOString(),files:[]};
  for(const rel of Object.keys(FILES)){const source=relPath(root,rel);if(!existsSync(source))continue;const target=relPath(backupRoot,rel);mkdirSync(dirname(target),{recursive:true});const data=readFileSync(source);writeFileSync(target,data);manifest.files.push({path:rel,sha256:digest(data)});}
  writeFileSync(join(backupRoot,'manifest.json'),JSON.stringify(manifest,null,2)+'\n','utf8');
  return backupRoot;
}

function applyFiles(root){
  const rootEol=detectEol(readFileSync(join(root,'package.json')));const changed=[];
  for(const [rel,entry] of Object.entries(FILES)){
    const path=relPath(root,rel);const current=existsSync(path)?readFileSync(path):undefined;const eol=current?detectEol(current):rootEol;
    const data=withEol(payload(entry),eol);mkdirSync(dirname(path),{recursive:true});
    const temp=`${path}.refactor013g-${process.pid}.tmp`;writeFileSync(temp,data);renameSync(temp,path);changed.push(rel);
  }
  return changed;
}

function rollback(root,backupRoot){
  log('검증 실패로 변경 파일을 롤백합니다.');
  for(const [rel,entry] of Object.entries(FILES)){
    const path=relPath(root,rel);const saved=relPath(backupRoot,rel);
    if(existsSync(saved)){mkdirSync(dirname(path),{recursive:true});writeFileSync(path,readFileSync(saved));}
    else if(entry.newFile&&existsSync(path))unlinkSync(path);
  }
}

function run(root,label,command,args,critical=true){
  log(label);
  const result=spawnSync(command,args,{cwd:root,stdio:'inherit',shell:process.platform==='win32',env:process.env});
  if(result.error){
    if(result.error.code==='ENOENT'){if(critical)return{ok:false,error:`${command} 실행 파일 없음`};log(`[환경 경고] ${command} 실행 파일을 찾지 못했습니다.`);return{ok:true,skipped:true};}
    return critical?{ok:false,error:String(result.error)}:{ok:true,skipped:true};
  }
  return{ok:result.status===0,status:result.status??-1};
}

function externalValidation(root){
  if(skipExternal){log('DROP8_PATCH_SKIP_EXTERNAL_VALIDATION=1: 외부 검증 생략');return;}
  const pnpm=process.platform==='win32'?'pnpm.cmd':'pnpm';
  const checks=[
    ['pnpm run typecheck',pnpm,['run','typecheck']],
    ['pnpm run lint',pnpm,['run','lint']],
    ['pnpm run test',pnpm,['run','test']],
    ['pnpm run build',pnpm,['run','build']],
  ];
  for(const [label,command,args] of checks){const result=run(root,label,command,args,true);if(!result.ok)fail(`${label} 실패 (exit=${result.status??'unknown'}${result.error?`, ${result.error}`:''})`);}
  const targets=Object.keys(FILES);
  const diff=run(root,'git diff --check (Refactor 013G 변경 파일)','git',['diff','--check','--',...targets],true);if(!diff.ok)fail(`git diff --check 실패 (exit=${diff.status??'unknown'})`);
  run(root,'git status --short','git',['status','--short'],false);
}

const root=findRoot();log(`프로젝트 루트: ${root}`);
try{
  prerequisiteCheck(root);
  const state=inspect(root);const total=Object.keys(FILES).length;
  if(state.final.length===total){log('이미 적용되어 있습니다.');process.exit(0);}
  if(state.final.length>0)fail(`부분 적용 상태 감지: 완료 ${state.final.length}/${total}. 완료 파일: ${state.final.join(', ')}`);
  if(state.conflicts.length)fail(`기준 문맥/해시 검증 실패:\n- ${state.conflicts.join('\n- ')}`);
  const expectedBaseline=Object.entries(FILES).filter(([,entry])=>!entry.newFile).length;
  if(state.baseline.length!==expectedBaseline)fail(`기준 파일 검증 수 불일치: ${state.baseline.length}/${expectedBaseline}`);
  if(state.absent.length!==Object.values(FILES).filter((entry)=>entry.newFile).length)fail('신규 파일 상태 검증 불일치');
  log(`사전 검증 성공: 기존 파일 ${state.baseline.length}개 수정, 신규 파일 ${state.absent.length}개 생성 예정`);
  log('단계: 현재 방 표시 → 공용 시야 복구 → 실내 전리품 216 → 물 경계 → 오토바이 8대 분산 → 테스트/문서');
  if(dryRun){log('dry-run 성공. 어떤 파일도 수정하지 않았습니다.');process.exit(0);}
  const backupRoot=backup(root);log(`백업: ${backupRoot}`);
  try{applyFiles(root);validateFinalFiles(root);externalValidation(root);}
  catch(error){rollback(root,backupRoot);throw error;}
  log(`적용 성공: ${Object.keys(FILES).length}개 파일`);
  log('8번 부두: 전리품 후보 264 · 활성 216 · 실내 124(57.4%) · 오토바이 후보 12 · 활성 8');
  log('현재 방 완전 표시 · 다른 방 개별 음영 · 물 경계/여울/상륙 표식 강화');
}catch(error){console.error(`[Refactor 013G] 실패: ${error instanceof Error?error.message:String(error)}`);process.exitCode=1;}
